import React, { useState, useEffect, useRef } from "react";
import { T } from "../../assets/styles/theme";
import { Btn, Card, Badge, Avatar, Input, Select, StatCard, Table, Tabs, ProgressBar, DonutChart, MiniBarChart, PageHeader, ProfileAlert, Modal, calcProfileCompletion } from "../../components/UI";
import { DashLayout } from "../../components/Layout";
import { TeacherForum } from "../Forum";
import {
  getTeacherProfile, updateTeacherProfile,
  getTeacherCourses, getTeacherAssignments,
  getSubmissionsForAssignment, gradeSubmission,
  markAttendance, getAttendanceForDate,
  createTeacherAnnouncement, getTeacherNotifications,
  getActiveDepartments, getTeacherStudents,
  getParentProfile, updateParentProfile,
  getMyChildren, linkChild,
  getChildFees,
  getParentNotifications,
  getTeacherMaterials, uploadMaterial, toggleMaterialVisibility, deleteMaterial,
} from "../../api/auth";

// ════════════════════════════════════════════════════════════════════════════════
// TEACHER PAGES
// ════════════════════════════════════════════════════════════════════════════════

export const TeacherOverview = () => (
  <div className="fade-up">
    <PageHeader title="Teacher Dashboard" subtitle="Welcome, Prof. Priya! Here's your teaching overview." />
    <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 18, marginBottom: 24 }}>
      <StatCard icon="👨‍🎓" label="Total Students" value="248" change="Across 4 courses" color={T.accent} />
      <StatCard icon="📚" label="Active Courses" value="4" change="2 live this week" color={T.primaryL} />
      <StatCard icon="📝" label="Pending Grading" value="12" change="Assignments to grade" color={T.accentY} />
      <StatCard icon="⭐" label="My Rating" value="4.8" change="By students" color={T.accentG} />
    </div>
    <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: 20 }}>
      <div>
        <Card style={{ marginBottom: 20 }}>
          <div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 15, marginBottom: 16 }}>My Courses</div>
          {[{ icon: "💻", title: "Full Stack Web Development", students: 82, progress: 72, pending: 5 }, { icon: "📊", title: "Data Science & ML", students: 96, progress: 55, pending: 7 }].map(c => (
            <div key={c.title} style={{ background: T.bg3, borderRadius: 12, padding: 16, marginBottom: 12 }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
                <div><div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 14 }}>{c.title}</div><div style={{ fontSize: 12, color: T.muted, marginTop: 2 }}>CS Department</div></div>
                <Badge type="success">Active</Badge>
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 10 }}>
                {[["Students", c.students, T.accent], ["Avg Progress", `${c.progress}%`, T.primaryL], ["Pending", c.pending, T.accentY]].map(([l, v, co]) => (
                  <div key={l} style={{ background: T.card, borderRadius: 8, padding: 10, textAlign: "center" }}>
                    <div style={{ fontFamily: "Syne", fontSize: 18, fontWeight: 800, color: co }}>{v}</div>
                    <div style={{ fontSize: 11, color: T.muted }}>{l}</div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </Card>
        <Card>
          <div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 15, marginBottom: 14 }}>Recent Submissions</div>
          <Table columns={["Student", "Assignment", "Submitted", "Action"]} rows={[
            [<div style={{ display: "flex", gap: 8, alignItems: "center" }}><Avatar name="Ananya Reddy" size={26} />Ananya R</div>, "EDA Analysis", "2 hrs ago", <Btn size="xs" variant="primary">Grade</Btn>],
            [<div style={{ display: "flex", gap: 8, alignItems: "center" }}><Avatar name="Rahul Mehta" size={26} />Rahul M</div>, "JS Quiz", "5 hrs ago", <Btn size="xs" variant="primary">Grade</Btn>],
          ]} />
        </Card>
      </div>
      <div>
        <Card style={{ marginBottom: 18 }}>
          <div style={{ fontFamily: "Syne", fontWeight: 700, marginBottom: 14 }}>Today's Schedule</div>
          {[{ time: "09:00 AM", title: "Full Stack Live Class", sub: "82 students · Google Meet", color: T.primary }, { time: "02:00 PM", title: "Data Science Lab", sub: "96 students · Lab 2", color: T.accent }, { time: "04:00 PM", title: "Assignment Review", sub: "1-on-1 sessions", color: T.accentY }].map(s => (
            <div key={s.title} style={{ display: "flex", gap: 12, padding: "10px 0", borderBottom: `1px solid rgba(45,33,96,.3)`, alignItems: "center" }}>
              <div style={{ fontSize: 12, fontWeight: 700, color: s.color, minWidth: 64 }}>{s.time}</div>
              <div style={{ width: 10, height: 10, borderRadius: "50%", background: s.color, flexShrink: 0 }} />
              <div><div style={{ fontSize: 13, fontWeight: 600 }}>{s.title}</div><div style={{ fontSize: 11, color: T.muted }}>{s.sub}</div></div>
            </div>
          ))}
        </Card>
        <Card>
          <div style={{ fontFamily: "Syne", fontWeight: 700, marginBottom: 14 }}>Student Ratings</div>
          <div style={{ textAlign: "center", padding: "10px 0" }}>
            <div style={{ fontFamily: "Syne", fontSize: 52, fontWeight: 900, color: T.accentY }}>4.8</div>
            <div style={{ fontSize: 22, color: T.accentY }}>★★★★★</div>
            <div style={{ fontSize: 12, color: T.muted, marginTop: 6 }}>Based on 186 student reviews</div>
          </div>
        </Card>
      </div>
    </div>
  </div>
);

// ── DYNAMIC: Profile fetches real data + department dropdown from DB ───────────
export const TeacherProfile = () => {
  const [form, setForm]       = useState({ name: "", email: "", phone: "", address: "", department: "", qualification: "", gender: "" });
  const [depts, setDepts]     = useState([]);
  const [saving, setSaving]   = useState(false);
  const [loading, setLoading] = useState(true);
  const { pct, missing }      = calcProfileCompletion("teacher", form);

  useEffect(() => {
    Promise.all([getTeacherProfile(), getActiveDepartments()])
      .then(([p, d]) => {
        setForm({ name: p?.name || "", email: p?.email || "", phone: p?.phone || "", address: p?.address || "", department: p?.department || "", qualification: p?.qualification || "", gender: p?.gender || "", userId: p?.userId || "" });
        setDepts(Array.isArray(d) ? d : []);
      }).catch(console.error).finally(() => setLoading(false));
  }, []);

  const handleSave = async () => {
    try { setSaving(true); await updateTeacherProfile({ name: form.name, phone: form.phone, address: form.address, department: form.department, qualification: form.qualification, gender: form.gender }); alert("Profile updated!"); }
    catch (err) { alert("Failed: " + err.message); } finally { setSaving(false); }
  };

  if (loading) return <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>;

  return (
    <div className="fade-up">
      <PageHeader title="My Profile" />
      <ProfileAlert pct={pct} missing={missing} onComplete={() => {}} />
      <div style={{ display: "grid", gridTemplateColumns: "1fr 2fr", gap: 24 }}>
        <Card style={{ textAlign: "center", padding: 32 }}>
          <DonutChart pct={pct} color={T.accentG} label="Complete" />
          <Avatar name={form.name || "T"} size={80} color={T.accentG} />
          <div style={{ fontFamily: "Syne", fontSize: 18, fontWeight: 800, marginTop: 12 }}>{form.name || "—"}</div>
          <div style={{ fontSize: 13, color: T.muted }}>{form.userId || "—"}</div>
          {form.department && <Badge type="success">{form.department}</Badge>}
          <Btn variant="dark" size="sm" full style={{ marginTop: 16 }}>📷 Upload Photo (Optional)</Btn>
        </Card>
        <Card style={{ padding: 28 }}>
          <div style={{ fontFamily: "Syne", fontSize: 17, fontWeight: 800, marginBottom: 20 }}>Update Profile</div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
            <Input label="Full Name *"     value={form.name}          onChange={e => setForm(f => ({ ...f, name: e.target.value }))} placeholder="Full name" />
            <Input label="Email"           value={form.email}         onChange={() => {}} style={{ opacity: 0.6, cursor: "not-allowed" }} />
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
            <Input label="Mobile Number *" value={form.phone}         onChange={e => setForm(f => ({ ...f, phone: e.target.value }))} placeholder="+91 98765 43210" />
            <Input label="Qualification *" value={form.qualification} onChange={e => setForm(f => ({ ...f, qualification: e.target.value }))} placeholder="e.g. M.Tech, PhD" />
          </div>
          <Select label="Department *" value={form.department} onChange={e => setForm(f => ({ ...f, department: e.target.value }))}
            options={[{ value: "", label: "-- Select Department --" }, ...depts.map(d => ({ value: d.name, label: d.name }))]} />
          <Select label="Gender" value={form.gender} onChange={e => setForm(f => ({ ...f, gender: e.target.value }))}
            options={[{ value: "", label: "Select" }, "Male", "Female", "Other"].map(o => typeof o === "string" ? { value: o, label: o } : o)} />
          <Input label="Address *" value={form.address} onChange={e => setForm(f => ({ ...f, address: e.target.value }))} placeholder="Street address" />
          <Btn variant="success" size="lg" onClick={handleSave} disabled={saving}>{saving ? "Saving…" : "Save Profile →"}</Btn>
        </Card>
      </div>
    </div>
  );
};

// ── DYNAMIC: Courses fetched from DB ──────────────────────────────────────────
export const TeacherCourses = () => {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { getTeacherCourses().then(d => setCourses(Array.isArray(d) ? d : [])).catch(console.error).finally(() => setLoading(false)); }, []);

  if (loading) return <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>;

  return (
    <div className="fade-up">
      <PageHeader title="My Courses & Content" actions={[<Btn variant="primary">+ Upload Content</Btn>]} />
      {courses.length === 0 ? (
        <Card><div style={{ padding: 32, textAlign: "center", color: T.muted }}>No courses assigned yet. Contact admin.</div></Card>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20 }}>
          {courses.map(c => (
            <Card key={c.id} style={{ padding: 22 }}>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 14 }}>
                <div><div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 15 }}>📚 {c.title}</div><div style={{ fontSize: 12, color: T.muted, marginTop: 2 }}>{c.department || "—"} · {c.durationHours}h</div></div>
                <Badge type={c.status === "ACTIVE" ? "success" : "warning"}>{c.status}</Badge>
              </div>
              <div style={{ border: `2px dashed ${T.border}`, borderRadius: 12, padding: 24, textAlign: "center", cursor: "pointer", marginBottom: 14, transition: "all .2s" }}
                onMouseEnter={e => { e.currentTarget.style.borderColor = T.primary; e.currentTarget.style.background = `${T.primary}08`; }}
                onMouseLeave={e => { e.currentTarget.style.borderColor = T.border; e.currentTarget.style.background = "transparent"; }}
                onClick={() => alert("Upload PDF notes, MP4 videos, or assignments")}>
                <div style={{ fontSize: 32, marginBottom: 8 }}>📤</div>
                <div style={{ fontWeight: 600, fontSize: 14 }}>Upload Content</div>
                <div style={{ fontSize: 12, color: T.muted, marginTop: 4 }}>PDF notes, MP4 videos, or assignments</div>
              </div>
              <div style={{ display: "flex", gap: 8 }}>
                <Btn size="xs" variant="ghost" full>📄 Notes</Btn>
                <Btn size="xs" variant="ghost" full>🎥 Videos</Btn>
                <Btn size="xs" variant="ghost" full>📝 Tasks</Btn>
              </div>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
};

export const TeacherLiveClasses = () => {
  const [courses, setCourses]       = useState([]);
  const [selected, setSelected]     = useState(null);
  const [materials, setMaterials]   = useState([]);
  const [tab, setTab]               = useState("ALL");
  const [modal, setModal]           = useState(false);
  const [saving, setSaving]         = useState(false);
  const [loading, setLoading]       = useState(false);
  const [fileInfo, setFileInfo]     = useState(null); // { name, size, base64, mimeType }
  const fileRef                     = React.useRef();
  const [form, setForm] = useState({
    type: "NOTE", title: "", description: "", content: "", scheduledAt: "",
  });

  useEffect(() => {
    getTeacherCourses()
      .then(d => setCourses(Array.isArray(d) ? d : []))
      .catch(console.error);
  }, []);

  const loadMaterials = (course) => {
    setLoading(true);
    getTeacherMaterials(course.id)
      .then(d => setMaterials(Array.isArray(d) ? d : []))
      .catch(console.error)
      .finally(() => setLoading(false));
  };

  const openCourse = (course) => {
    setSelected(course);
    setTab("ALL");
    loadMaterials(course);
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const maxMB = 10;
    if (file.size > maxMB * 1024 * 1024) {
      alert(`File too large. Maximum size is ${maxMB}MB.`);
      return;
    }
    const reader = new FileReader();
    reader.onload = () => {
      setFileInfo({ name: file.name, size: file.size, base64: reader.result, mimeType: file.type });
      setForm(f => ({ ...f, content: reader.result }));
      // Auto-fill title from filename if empty
      setForm(f => ({ ...f, content: reader.result, title: f.title || file.name.replace(/\.[^/.]+$/, "") }));
    };
    reader.readAsDataURL(file);
  };

  const resetModal = () => {
    setModal(false);
    setForm({ type: "NOTE", title: "", description: "", content: "", scheduledAt: "" });
    setFileInfo(null);
    if (fileRef.current) fileRef.current.value = "";
  };

  const handleUpload = async () => {
    if (!form.title.trim()) { alert("Title is required."); return; }
    if (form.type === "NOTE" && !form.content) { alert("Please select a document to upload."); return; }
    if (form.type !== "NOTE" && !form.content.trim()) { alert("Content / URL is required."); return; }
    try {
      setSaving(true);
      await uploadMaterial({ ...form, courseId: selected.id });
      resetModal();
      loadMaterials(selected);
    } catch (err) { alert("Error: " + err.message); }
    finally { setSaving(false); }
  };

  const handleToggle = async (id) => {
    await toggleMaterialVisibility(id).catch(console.error);
    loadMaterials(selected);
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this material?")) return;
    await deleteMaterial(id).catch(console.error);
    loadMaterials(selected);
  };

  const typeIcon  = { NOTE: "📝", VIDEO: "🎥", LIVE: "🔗" };
  const typeColor = { NOTE: T.accent, VIDEO: T.primaryL, LIVE: T.accentG };
  const typeLabel = { NOTE: "Written Note", VIDEO: "Video", LIVE: "Live Class Link" };

  const filtered = tab === "ALL" ? materials : materials.filter(m =>
    tab === "LIVE" ? m.type === "MEET_LINK" : m.type === tab
  );

  // ── Course list view ───────────────────────────────────────────────────────
  if (!selected) return (
    <div className="fade-up">
      <PageHeader title="Learning Board" subtitle="Select a course to manage its materials" />
      {courses.length === 0 ? (
        <Card><div style={{ padding: 40, textAlign: "center", color: T.muted }}>
          <div style={{ fontSize: 40, marginBottom: 10 }}>📭</div>
          <div style={{ fontFamily: "Syne", fontWeight: 700 }}>No courses assigned yet.</div>
        </div></Card>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 18 }}>
          {courses.map(c => (
            <Card key={c.id} style={{ padding: 0, overflow: "hidden" }}>
              <div style={{ height: 5, background: `linear-gradient(90deg, ${T.primary}, ${T.accent})` }} />
              <div style={{ padding: 20 }}>
                <div style={{ fontFamily: "Syne", fontWeight: 800, fontSize: 15, marginBottom: 6 }}>{c.title}</div>
                <div style={{ fontSize: 12, color: T.muted, marginBottom: 12 }}>
                  🏢 {c.department || "—"} · ⏱ {c.durationHours || 0}h
                </div>
                <div style={{ display: "flex", gap: 8 }}>
                  {["📝 Notes", "🎥 Videos", "🔗 Live"].map(lbl => (
                    <span key={lbl} style={{ fontSize: 11, background: T.bg3, borderRadius: 6,
                      padding: "3px 8px", color: T.muted }}>{lbl}</span>
                  ))}
                </div>
                <Btn size="xs" variant="primary" full style={{ marginTop: 12 }} onClick={() => openCourse(c)}>
                  Open Course Board →
                </Btn>
              </div>
            </Card>
          ))}
        </div>
      )}
    </div>
  );

  // ── Course board view ──────────────────────────────────────────────────────
  return (
    <div className="fade-up">
      <PageHeader
        title={selected.title}
        subtitle="Learning Board — manage notes, videos & live class links"
        actions={[
          <Btn size="sm" variant="ghost" onClick={() => setSelected(null)}>← All Courses</Btn>,
          <Btn variant="primary" onClick={() => setModal(true)}>+ Upload Material</Btn>,
        ]}
      />

      {/* Tab filter */}
      <div style={{ display: "flex", gap: 8, marginBottom: 20, flexWrap: "wrap" }}>
        {[
          { key: "ALL",   label: `All (${materials.length})` },
          { key: "NOTE",  label: `📝 Notes (${materials.filter(m => m.type === "NOTE").length})` },
          { key: "VIDEO", label: `🎥 Videos (${materials.filter(m => m.type === "VIDEO").length})` },
          { key: "LIVE",  label: `🔗 Live Classes (${materials.filter(m => m.type === "MEET_LINK").length})` },
        ].map(t => (
          <button key={t.key} onClick={() => setTab(t.key)}
            style={{ padding: "7px 16px", borderRadius: 50,
              border: `1.5px solid ${tab === t.key ? T.primary : T.border}`,
              background: tab === t.key ? `${T.primary}20` : "transparent",
              color: tab === t.key ? T.primary : T.muted,
              fontWeight: 700, fontSize: 12, cursor: "pointer" }}>
            {t.label}
          </button>
        ))}
      </div>

      {/* Materials */}
      {loading ? (
        <div style={{ padding: 40, textAlign: "center", color: T.muted }}>Loading…</div>
      ) : filtered.length === 0 ? (
        <Card><div style={{ padding: 32, textAlign: "center", color: T.muted }}>
          <div style={{ fontSize: 36, marginBottom: 8 }}>📭</div>
          <div>No {tab === "ALL" ? "materials" : tab.toLowerCase() + "s"} uploaded yet.</div>
          <Btn size="sm" variant="primary" style={{ marginTop: 12 }} onClick={() => { setForm(f => ({ ...f, type: tab === "LIVE" ? "MEET_LINK" : tab === "ALL" ? "NOTE" : tab })); setModal(true); }}>
            + Upload Now
          </Btn>
        </div></Card>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(320px, 1fr))", gap: 16 }}>
          {filtered.map(m => {
            const displayType = m.type === "MEET_LINK" ? "LIVE" : m.type;
            return (
              <Card key={m.id} style={{ padding: 0, overflow: "hidden", opacity: m.visible ? 1 : 0.55 }}>
                <div style={{ height: 4, background: `linear-gradient(90deg, ${typeColor[displayType]}, ${T.primary})` }} />
                <div style={{ padding: 16 }}>
                  <div style={{ display: "flex", gap: 10, alignItems: "flex-start", marginBottom: 10 }}>
                    <div style={{ width: 36, height: 36, borderRadius: 10, background: `${typeColor[displayType]}20`,
                      display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, flexShrink: 0 }}>
                      {typeIcon[displayType]}
                    </div>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontWeight: 800, fontSize: 14, fontFamily: "Syne" }}>{m.title}</div>
                      <div style={{ fontSize: 11, color: T.muted }}>{new Date(m.createdAt).toLocaleDateString("en-IN")}</div>
                    </div>
                    <Badge type={m.visible ? "success" : "warning"}>{m.visible ? "Live" : "Hidden"}</Badge>
                  </div>

                  {m.description && <div style={{ fontSize: 12, color: T.muted, marginBottom: 8 }}>{m.description}</div>}

                  {m.type === "NOTE" && (() => {
                    // Detect if content is a base64 file or plain text
                    const isFile = m.content?.startsWith("data:");
                    if (isFile) {
                      const mimeMatch = m.content.match(/^data:([^;]+);/);
                      const mime = mimeMatch?.[1] || "";
                      const ext = mime.includes("pdf") ? "pdf" : mime.includes("word") ? "docx" :
                                  mime.includes("sheet") ? "xlsx" : mime.includes("presentation") ? "pptx" : "txt";
                      const icon = mime.includes("pdf") ? "📕" : mime.includes("word") ? "📘" :
                                   mime.includes("sheet") ? "📗" : mime.includes("presentation") ? "📙" : "📄";
                      return (
                        <div style={{ background: `${T.accent}10`, border: `1px solid ${T.accent}30`,
                          borderRadius: 8, padding: "10px 12px", display: "flex", alignItems: "center",
                          gap: 10, marginBottom: 8 }}>
                          <span style={{ fontSize: 24 }}>{icon}</span>
                          <div style={{ flex: 1, fontSize: 12, color: T.muted }}>Document · {ext.toUpperCase()}</div>
                          <a href={m.content} download={`${m.title}.${ext}`}
                            style={{ fontSize: 11, background: T.accent, color: "#fff",
                              borderRadius: 6, padding: "4px 10px", textDecoration: "none", fontWeight: 700 }}>
                            ⬇ Download
                          </a>
                        </div>
                      );
                    }
                    return (
                      <div style={{ background: T.bg3, borderRadius: 8, padding: "8px 12px", fontSize: 12,
                        maxHeight: 70, overflow: "hidden", whiteSpace: "pre-wrap", color: T.text, marginBottom: 8 }}>
                        {m.content?.substring(0, 150)}{m.content?.length > 150 ? "…" : ""}
                      </div>
                    );
                  })()}
                  {m.type === "VIDEO" && (
                    <a href={m.content} target="_blank" rel="noreferrer"
                      style={{ display: "block", background: T.bg3, borderRadius: 8, padding: "8px 12px",
                        fontSize: 12, color: T.primaryL, textDecoration: "none", marginBottom: 8,
                        overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                      🎥 {m.content}
                    </a>
                  )}
                  {m.type === "MEET_LINK" && (
                    <div style={{ background: `${T.accentG}10`, borderRadius: 8, padding: "8px 12px", marginBottom: 8 }}>
                      {m.scheduledAt && <div style={{ fontSize: 11, color: T.muted, marginBottom: 4 }}>
                        📅 {new Date(m.scheduledAt).toLocaleString("en-IN")}
                      </div>}
                      <a href={m.content} target="_blank" rel="noreferrer"
                        style={{ fontSize: 12, color: T.accentG, fontWeight: 700, textDecoration: "none" }}>
                        🔗 {m.content?.substring(0, 40)}…
                      </a>
                    </div>
                  )}

                  <div style={{ display: "flex", gap: 8 }}>
                    <Btn size="xs" variant="ghost" onClick={() => handleToggle(m.id)}>
                      {m.visible ? "🙈 Hide" : "👁 Show"}
                    </Btn>
                    <Btn size="xs" variant="danger" onClick={() => handleDelete(m.id)}>🗑</Btn>
                  </div>
                </div>
              </Card>
            );
          })}
        </div>
      )}

      {/* Upload Modal */}
      <Modal open={modal} onClose={resetModal} title={`Upload to ${selected.title}`}>
        {/* Type buttons */}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8, marginBottom: 16 }}>
          {(["NOTE", "VIDEO", "MEET_LINK"]).map(t => {
            const dt = t === "MEET_LINK" ? "LIVE" : t;
            return (
              <button key={t} onClick={() => setForm(f => ({ ...f, type: t }))}
                style={{ padding: "12px 0", borderRadius: 10,
                  border: `2px solid ${form.type === t ? typeColor[dt] : T.border}`,
                  background: form.type === t ? `${typeColor[dt]}18` : T.bg3,
                  color: form.type === t ? typeColor[dt] : T.muted,
                  fontWeight: 700, fontSize: 12, cursor: "pointer", textAlign: "center" }}>
                <div style={{ fontSize: 20 }}>{typeIcon[dt]}</div>
                {typeLabel[t]}
              </button>
            );
          })}
        </div>

        <Input label="Title *"
          placeholder={form.type === "NOTE" ? "e.g. Chapter 3 — Arrays & Loops" :
            form.type === "VIDEO" ? "e.g. Lecture 5 — Recursion" : "e.g. Week 3 Live Session"}
          value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} />

        <Input label="Description (optional)"
          placeholder="Brief description for students"
          value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} />

        {form.type === "NOTE" && (
          <div style={{ marginBottom: 14 }}>
            <label style={{ fontSize: 11, fontWeight: 700, color: T.muted, textTransform: "uppercase",
              letterSpacing: 1, display: "block", marginBottom: 8 }}>Upload Document *</label>

            {/* Hidden file input */}
            <input ref={fileRef} type="file"
              accept=".pdf,.doc,.docx,.txt,.ppt,.pptx,.xls,.xlsx"
              style={{ display: "none" }}
              onChange={handleFileChange} />

            {/* Drop zone / picker */}
            {!fileInfo ? (
              <div onClick={() => fileRef.current?.click()}
                style={{ border: `2px dashed ${T.border}`, borderRadius: 12, padding: "28px 20px",
                  textAlign: "center", cursor: "pointer", background: T.bg3,
                  transition: "border-color .2s" }}
                onMouseEnter={e => e.currentTarget.style.borderColor = T.primary}
                onMouseLeave={e => e.currentTarget.style.borderColor = T.border}>
                <div style={{ fontSize: 36, marginBottom: 8 }}>📄</div>
                <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 4 }}>Click to select a document</div>
                <div style={{ fontSize: 12, color: T.muted }}>PDF, Word, PowerPoint, Excel, TXT · Max 10MB</div>
              </div>
            ) : (
              /* File selected — show preview */
              <div style={{ background: `${T.accentG}10`, border: `1.5px solid ${T.accentG}40`,
                borderRadius: 12, padding: "14px 16px", display: "flex", gap: 14, alignItems: "center" }}>
                <div style={{ fontSize: 32 }}>
                  {fileInfo.mimeType?.includes("pdf") ? "📕" :
                   fileInfo.mimeType?.includes("word") || fileInfo.name?.endsWith(".docx") ? "📘" :
                   fileInfo.mimeType?.includes("sheet") || fileInfo.name?.endsWith(".xlsx") ? "📗" :
                   fileInfo.mimeType?.includes("presentation") || fileInfo.name?.endsWith(".pptx") ? "📙" : "📄"}
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 700, fontSize: 13 }}>{fileInfo.name}</div>
                  <div style={{ fontSize: 11, color: T.muted, marginTop: 2 }}>
                    {(fileInfo.size / 1024).toFixed(1)} KB · Ready to upload
                  </div>
                </div>
                <button onClick={() => { setFileInfo(null); setForm(f => ({ ...f, content: "" })); if (fileRef.current) fileRef.current.value = ""; }}
                  style={{ background: "transparent", border: "none", cursor: "pointer", color: T.muted, fontSize: 18 }}>✕</button>
              </div>
            )}
          </div>
        )}

        {form.type === "VIDEO" && (
          <Input label="Video URL * (YouTube / Google Drive / any link)"
            placeholder="https://youtube.com/watch?v=..."
            value={form.content} onChange={e => setForm(f => ({ ...f, content: e.target.value }))} />
        )}

        {form.type === "MEET_LINK" && (
          <>
            <Select label="Platform"
              value={form.content.includes("zoom") ? "zoom" : form.content.includes("teams") ? "teams" : "meet"}
              onChange={() => {}}
              options={[{ value: "meet", label: "Google Meet" }, { value: "zoom", label: "Zoom" }, { value: "teams", label: "Microsoft Teams" }]} />
            <Input label="Meeting Link *"
              placeholder="https://meet.google.com/abc-defg-hij"
              value={form.content} onChange={e => setForm(f => ({ ...f, content: e.target.value }))} />
            <Input label="Scheduled Date & Time" type="datetime-local"
              value={form.scheduledAt} onChange={e => setForm(f => ({ ...f, scheduledAt: e.target.value }))} />
          </>
        )}

        <Btn variant="primary" full size="lg" onClick={handleUpload} disabled={saving}>
          {saving ? "Uploading…" : `Upload ${typeLabel[form.type]} →`}
        </Btn>
      </Modal>
    </div>
  );
};

// ── DYNAMIC: Real students loaded; real attendance saved to DB ────────────────
export const TeacherAttendance = () => {
  const [courses, setCourses]     = useState([]);
  const [courseId, setCourseId]   = useState("");
  const [date, setDate]           = useState(new Date().toISOString().slice(0, 10));
  const [students, setStudents]   = useState([]);
  const [statusMap, setStatusMap] = useState({});
  const [saving, setSaving]       = useState(false);

  useEffect(() => {
    Promise.all([getTeacherCourses(), getTeacherStudents()])
      .then(([c, s]) => { setCourses(Array.isArray(c) ? c : []); setStudents(Array.isArray(s) ? s : []); })
      .catch(console.error);
  }, []);

  useEffect(() => {
    if (!courseId || !date) return;
    getAttendanceForDate(courseId, date)
      .then(records => { const map = {}; if (Array.isArray(records)) records.forEach(r => { map[r.student?.id] = r.status; }); setStatusMap(map); })
      .catch(console.error);
  }, [courseId, date]);

  const handleSave = async () => {
    if (!courseId) { alert("Select a course first."); return; }
    try {
      setSaving(true);
      await markAttendance({ courseId: Number(courseId), date, entries: students.map(s => ({ studentId: s.id, status: statusMap[s.id] || "PRESENT" })) });
      alert("Attendance saved successfully!");
    } catch (err) { alert("Error: " + err.message); } finally { setSaving(false); }
  };

  return (
    <div className="fade-up">
      <PageHeader title="Attendance Monitor" />
      <Card style={{ marginBottom: 20 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <div style={{ fontFamily: "Syne", fontWeight: 700 }}>Mark Attendance</div>
          <div style={{ display: "flex", gap: 8 }}>
            <Btn size="sm" variant="success" onClick={() => { const m = {}; students.forEach(s => { m[s.id] = "PRESENT"; }); setStatusMap(m); }}>Mark All Present</Btn>
            <Btn size="sm" variant="ghost" onClick={handleSave} disabled={saving}>{saving ? "Saving…" : "Save Attendance"}</Btn>
          </div>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
          <Select label="Course *" value={courseId} onChange={e => setCourseId(e.target.value)}
            options={[{ value: "", label: "-- Select Course --" }, ...courses.map(c => ({ value: String(c.id), label: c.title }))]} />
          <Input label="Date *" type="date" value={date} onChange={e => setDate(e.target.value)} />
        </div>
      </Card>
      <Card>
        {students.length === 0
          ? <div style={{ padding: 24, textAlign: "center", color: T.muted }}>No students found.</div>
          : <Table columns={["Student", "ID", "Status", "Overall %", "Mark"]}
              rows={students.map(s => [
                <div style={{ display: "flex", gap: 8, alignItems: "center" }}><Avatar name={s.name} size={28} />{s.name}</div>,
                s.userId || `STU-${s.id}`,
                <Badge type={statusMap[s.id] === "ABSENT" ? "danger" : statusMap[s.id] === "LATE" ? "warning" : "success"}>{statusMap[s.id] || "Present"}</Badge>,
                "—",
                <select value={statusMap[s.id] || "PRESENT"} onChange={e => setStatusMap(m => ({ ...m, [s.id]: e.target.value }))}
                  style={{ background: T.bg3, border: `1px solid ${T.border}`, borderRadius: 6, color: T.text, padding: "4px 8px", fontSize: 12 }}>
                  <option value="PRESENT">Present</option>
                  <option value="ABSENT">Absent</option>
                  <option value="LATE">Late</option>
                </select>,
              ])}
            />
        }
      </Card>
    </div>
  );
};

// ── DYNAMIC: Real submissions loaded and graded via DB ────────────────────────
export const TeacherGrading = () => {
  const [assignments, setAssigns]     = useState([]);
  const [selectedId, setSelectedId]   = useState("");
  const [submissions, setSubmissions] = useState([]);
  const [grading, setGrading]         = useState({});

  useEffect(() => { getTeacherAssignments().then(d => setAssigns(Array.isArray(d) ? d : [])).catch(console.error); }, []);

  const loadSubs = async (id) => {
    setSelectedId(id);
    if (!id) { setSubmissions([]); return; }
    try { setSubmissions(Array.isArray(await getSubmissionsForAssignment(id)) ? await getSubmissionsForAssignment(id) : []); } catch (err) { console.error(err); }
  };

  const handleGrade = async (subId) => {
    const { marks, feedback } = grading[subId] || {};
    if (!marks) { alert("Enter a score first."); return; }
    try {
      const updated = await gradeSubmission(subId, { marks: Number(marks), feedback: feedback || "" });
      setSubmissions(s => s.map(x => x.id === subId ? updated : x));
      alert("Graded!");
    } catch (err) { alert("Error: " + err.message); }
  };

  return (
    <div className="fade-up">
      <PageHeader title="Test Evaluation & Grading" />
      <Card style={{ marginBottom: 20 }}>
        <Select label="Select Assignment" value={selectedId} onChange={e => loadSubs(e.target.value)}
          options={[{ value: "", label: "-- Choose assignment to grade --" }, ...assignments.map(a => ({ value: String(a.id), label: `${a.title} (${a.course?.title || "—"})` }))]} />
      </Card>
      <Card>
        <div style={{ fontFamily: "Syne", fontWeight: 700, marginBottom: 16 }}>
          {selectedId ? `Submissions (${submissions.length})` : "Pending Assignments"}
        </div>
        {!selectedId ? (
          <div style={{ padding: 24, color: T.muted, textAlign: "center" }}>Select an assignment above to view submissions.</div>
        ) : submissions.length === 0 ? (
          <div style={{ padding: 24, textAlign: "center", color: T.muted }}>No submissions yet.</div>
        ) : (
          <Table columns={["Student", "Assignment", "Submitted", "Score /100", "Action"]}
            rows={submissions.map(s => [
              <div style={{ display: "flex", gap: 8, alignItems: "center" }}><Avatar name={s.student?.name || "S"} size={26} />{s.student?.name || "—"}</div>,
              s.assignment?.title || "—",
              s.submittedAt ? new Date(s.submittedAt).toLocaleString("en-IN", { dateStyle: "short", timeStyle: "short" }) : "—",
              s.status === "GRADED"
                ? <span style={{ color: T.accentG, fontWeight: 700 }}>✓ {s.marksObtained}</span>
                : <input type="number" placeholder="0-100" value={grading[s.id]?.marks || ""} onChange={e => setGrading(g => ({ ...g, [s.id]: { ...g[s.id], marks: e.target.value } }))}
                    style={{ width: 72, background: T.bg3, border: `1px solid ${T.border}`, borderRadius: 6, padding: "4px 8px", fontSize: 12, color: T.text }} />,
              s.status === "GRADED"
                ? <Btn size="xs" variant="success">Saved ✓</Btn>
                : <Btn size="xs" variant="primary" onClick={() => handleGrade(s.id)}>Save</Btn>,
            ])}
          />
        )}
      </Card>
    </div>
  );
};

