  if (loading) return <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>;
  if (children.length === 0) return <div className="fade-up"><PageHeader title="Course & Attendance Tracking" /><Card><div style={{ padding: 32, textAlign: "center", color: T.muted }}>No children linked yet.</div></Card></div>;

