// ── DYNAMIC: Real notifications, fallback to static if empty ──────────────────
export const ParentNotifications = () => {
  const [notifs, setNotifs]   = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { getParentNotifications().then(d => setNotifs(Array.isArray(d) ? d : [])).catch(console.error).finally(() => setLoading(false)); }, []);

  const staticFallback = [
    { id: "s1", icon: "✅", title: "Ananya scored 88/100 in JS Quiz",           message: "Full Stack Dev · 2 hrs ago",    read: false },
    { id: "s2", icon: "💳", title: "Fee Due: Lab Fee ₹4,500 — Due 30 Mar",      message: "Finance · 1 day ago",           read: false },
    { id: "s3", icon: "⚠️", title: "Vikram missed 2 classes this week",         message: "Attendance Alert · 2 days ago", read: false },
    { id: "s4", icon: "📢", title: "Exam scheduled for Ananya: Cyber Security", message: "Academic · 3 days ago",         read: true  },
  ];
  const items = notifs.length > 0 ? notifs : (loading ? [] : staticFallback);

  return (
    <div className="fade-up">
      <PageHeader title="Notifications" actions={[<Btn variant="ghost" size="sm">Mark All Read</Btn>]} />
      <Card>
        {loading ? <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>
          : items.map((n, i) => (
            <div key={n.id || i} style={{ display: "flex", gap: 14, padding: "12px 0", borderBottom: `1px solid rgba(45,33,96,.4)`, alignItems: "flex-start" }}>
              <div style={{ width: 38, height: 38, background: `${T.accentR}18`, borderRadius: 9, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, flexShrink: 0 }}>{n.icon || "🔔"}</div>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 14, fontWeight: n.read ? 500 : 700 }}>{n.title}</div>
                <div style={{ fontSize: 12, color: T.muted, marginTop: 2 }}>{n.message}</div>
              </div>
              {!n.read && <div style={{ width: 8, height: 8, borderRadius: "50%", background: T.accentR, flexShrink: 0, marginTop: 5 }} />}
            </div>
          ))
        }
      </Card>
    </div>
  );
};

// ─── PARENT DASHBOARD WRAPPER ─────────────────────────────────────────────────
const PARENT_PAGES = {
  overview:      { comp: ParentOverview      },
  profile:       { comp: ParentProfile       },
  children:      { comp: ParentChildren      },
  tracking:      { comp: ParentTracking      },
  results:       { comp: ParentResults       },
  fees:          { comp: ParentFees          },
  messages:      { comp: ParentMessages      },
  notifications: { comp: ParentNotifications },
};

export const ParentDashboard = ({ onLogout }) => {
  const [page, setPage]       = useState("overview");
  const [profile, setProfile] = useState(null);

  useEffect(() => { getParentProfile().then(setProfile).catch(console.error); }, []);

  const { pct, missing } = calcProfileCompletion("parent", profile || {});
  const { comp: Comp } = PARENT_PAGES[page] || PARENT_PAGES.overview;

  return (
    <DashLayout role="parent" page={page} onNav={setPage} onLogout={onLogout}>
      <ProfileAlert pct={pct} missing={missing} onComplete={() => setPage("profile")} />
      <Comp onNav={setPage} />
    </DashLayout>
  );
};
